import{_ as a,c as i,o as t,aN as e}from"./chunks/framework.CqA5BTDU.js";const r=JSON.parse('{"title":"系统初始化与目录结构","description":"","frontmatter":{},"headers":[],"relativePath":"01.Linux基础/01-系统初始化与目录结构.md","filePath":"01.Linux基础/01-系统初始化与目录结构.md","lastUpdated":null}'),n={name:"01.Linux基础/01-系统初始化与目录结构.md"};function h(p,s,d,l,k,o){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="系统初始化与目录结构" tabindex="-1">系统初始化与目录结构 <a class="header-anchor" href="#系统初始化与目录结构" aria-label="Permalink to &quot;系统初始化与目录结构&quot;">​</a></h1><p>拿到一台新机器（物理机、虚拟机、云主机），直接开始部署服务会埋下几个雷：主机名默认是 <code>localhost</code>，多台机器区分不开；时区是 UTC，日志时间对不上本地时间；系统版本和内核版本不清楚，装软件时选错包格式；目录结构不熟，出问题时不知道去哪里找日志和配置。</p><p>系统初始化的目的就是在部署业务之前，先把机器拉到同一个基准线上——版本明确、时钟同步、主机名有含义、目录结构心里有数。排障时第一步永远是确认环境信息，这些基础数据比任何高级诊断都先用到。</p><h2 id="一、发行版" tabindex="-1">一、发行版 <a class="header-anchor" href="#一、发行版" aria-label="Permalink to &quot;一、发行版&quot;">​</a></h2><p>Linux 服务器常见的发行版大致分为两个系列。不同系列的命令有差异，比如安装软件时 RHEL 系用 yum/dnf，Debian 系用 apt。</p><table tabindex="0"><thead><tr><th>系列</th><th>常见发行版</th><th>包管理</th><th>服务管理</th></tr></thead><tbody><tr><td>RHEL 系</td><td>RHEL、CentOS、Rocky、AlmaLinux</td><td>rpm / yum / dnf</td><td>systemd</td></tr><tr><td>Debian 系</td><td>Debian、Ubuntu</td><td>dpkg / apt</td><td>systemd</td></tr></tbody></table><p>查看当前系统的版本信息：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/os-release</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 发行版名称、版本号</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 内核版本、架构</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostnamectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 主机名、系统信息</span></span></code></pre></div><p><code>/etc/os-release</code> 是 freedesktop 规范的一部分，主流发行版都遵循。<code>uname -a</code> 看内核版本，有时候发行版相同但内核版本不同，命令参数也可能不一样。</p><p>排障时先把这两个命令的输出贴出来，能让后续的排查命令更准确。</p><h2 id="二、首次登录" tabindex="-1">二、首次登录 <a class="header-anchor" href="#二、首次登录" aria-label="Permalink to &quot;二、首次登录&quot;">​</a></h2><p>登录一台新机器后，先确认当前用户身份和登录来源：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 当前登录的用户名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # uid、gid、所属组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">w</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 当前在线用户及其操作</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">last</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 最近 5 条登录记录</span></span></code></pre></div><p><code>id</code> 的输出比 <code>whoami</code> 更完整——除了用户名，还能看到 uid、gid 和附加组列表。排查权限问题时，用户名本身不能说明全部权限，要看组关系。</p><p><code>w</code> 能看到当前有哪些用户在登录、从哪个 IP 来的、正在执行什么命令。<code>last</code> 看历史登录记录。如果在新机器上发现不认识的登录来源，需要保留记录再做处理。</p><h2 id="三、主机名" tabindex="-1">三、主机名 <a class="header-anchor" href="#三、主机名" aria-label="Permalink to &quot;三、主机名&quot;">​</a></h2><p>主机名用来在服务器之间区分身份。如果没有规划，多台机器都叫 <code>localhost</code>，批量管理和排查时容易混淆。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # 查看当前主机名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostnamectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 查看完整的主机名信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostnamectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-hostname</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web-01</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 设置新主机名</span></span></code></pre></div><p>命名通常遵循一定的规范，比如 <code>业务名-编号</code>（<code>web-01</code>、<code>mysql-02</code>），有的团队会在前面加上环境标识（<code>prod-web-01</code>）。具体用哪种看团队约定，重点是保持统一。</p><p>主机名修改后，建议同步检查 <code>/etc/hosts</code> 里是否有对应的解析记录，部分服务在启动时会依赖本机名解析。</p><h2 id="四、时间和时区" tabindex="-1">四、时间和时区 <a class="header-anchor" href="#四、时间和时区" aria-label="Permalink to &quot;四、时间和时区&quot;">​</a></h2><p>系统时间不准确会影响很多组件：日志时间戳错乱、TLS 证书校验失败、定时任务在不预期的时间执行、集群节点间时间偏差导致数据不一致。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timedatectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 查看时区、NTP 状态、当前时间</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timedatectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-timezone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Asia/Shanghai</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 设置时区</span></span></code></pre></div><p>时间同步服务推荐 chrony，比传统的 ntpd 同步更快、更适合偶尔断网的场景：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL / CentOS / Rocky</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chrony</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chronyd</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu / Debian</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chrony</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chrony</span></span></code></pre></div><p>检查同步状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chronyc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sources</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 查看时间源列表和状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chronyc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tracking</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 查看当前同步的详细指标</span></span></code></pre></div><p><code>chronyc sources -v</code> 输出的 <code>^*</code> 表示当前正在使用的时间源，<code>^+</code> 表示候选源。如果所有源前面都是 <code>^?</code>，说明没有成功连接到任何 NTP 服务器。</p><p>容器环境里需要注意：容器默认会继承宿主机的系统时间，但它自己的时区配置可能和宿主机不一样。遇到过宿主机时区是 Asia/Shanghai，容器里还是 UTC，两边日志时间对不上。</p><h2 id="五、目录结构" tabindex="-1">五、目录结构 <a class="header-anchor" href="#五、目录结构" aria-label="Permalink to &quot;五、目录结构&quot;">​</a></h2><p>Linux 的目录结构遵循 FHS（Filesystem Hierarchy Standard）。不需要全部背诵，但几个高频目录应该熟悉。</p><p><code>/etc</code> 集中了几乎所有系统和服务的配置文件。改配置、备份配置、排查&quot;配置为什么不生效&quot;时都会经常访问这个目录。</p><p><code>/var</code> 存放运行时数据，包括日志（<code>/var/log</code>）、缓存（<code>/var/cache</code>）、锁文件（<code>/var/lock</code>）等。日志目录最容易满，需要定期清理或做 logrotate。</p><p><code>/opt</code> 和 <code>/usr/local</code> 的区别：<code>/opt</code> 通常放第三方或独立的软件包，<code>/usr/local</code> 放手工编译安装的软件。实际使用中，很多运维习惯把自建服务放在 <code>/opt</code> 下，再配合软链接做版本管理。</p><p><code>/proc</code> 和 <code>/sys</code> 是虚拟文件系统，不占用磁盘空间，内容由内核在运行时动态生成。<code>/proc</code> 里的信息在排障时经常用到——<code>/proc/cpuinfo</code>、<code>/proc/meminfo</code>、<code>/proc/loadavg</code>、<code>/proc/PID/cmdline</code> 等等。</p><p><code>/tmp</code> 是临时文件目录。有一部分发行版配置了重启后清空 <code>/tmp</code>（通过 tmp.mount 或 systemd-tmpfiles），所以重要的东西不适合长期放在这里。</p><p>几个常用目录速查：</p><table tabindex="0"><thead><tr><th>目录</th><th>用途</th></tr></thead><tbody><tr><td><code>/etc</code></td><td>系统和服务配置</td></tr><tr><td><code>/var/log</code></td><td>各类日志</td></tr><tr><td><code>/opt</code></td><td>第三方软件</td></tr><tr><td><code>/usr/local</code></td><td>手工编译/部署的软件</td></tr><tr><td><code>/home</code></td><td>普通用户家目录</td></tr><tr><td><code>/root</code></td><td>root 用户家目录</td></tr><tr><td><code>/tmp</code></td><td>临时文件</td></tr><tr><td><code>/proc</code></td><td>内核和进程信息（虚拟）</td></tr><tr><td><code>/sys</code></td><td>设备和内核对象（虚拟）</td></tr><tr><td><code>/dev</code></td><td>设备文件</td></tr></tbody></table><h2 id="六、新机器基础检查" tabindex="-1">六、新机器基础检查 <a class="header-anchor" href="#六、新机器基础检查" aria-label="Permalink to &quot;六、新机器基础检查&quot;">​</a></h2><p>下面这些命令只读取信息、不会修改系统，新机器到手可以放心跑一遍：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/os-release</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 系统版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 内核版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostnamectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 主机名和系统信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timedatectl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 时区和时间状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 网卡和 IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 路由表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 磁盘使用情况</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 内存使用情况</span></span></code></pre></div><p>这些信息也是交接机器时需要收集的基本资料，完整的基线配置可以参考 <a href="/kb/01.Linux基础/17-系统初始化基线">系统初始化基线</a>。</p>`,42)])])}const g=a(n,[["render",h]]);export{r as __pageData,g as default};
